def classify_status(code: int) -> str:
    if 200 <= code < 300:
        return "ok"
    if code == 400:
        return "client_error_no_retry"
    if code >= 500:
        return "server_error_retry"
    return "other"
print(classify_status(400), classify_status(503), classify_status(200))

