import time
def fetch_with_retries(fn, max_attempts=3):
    for i in range(max_attempts):
        try:
            return fn()
        except TimeoutError:
            if i == max_attempts - 1:
                raise
            time.sleep(0.01 * (2 ** i))
print("retry solo timeouts/5xx, no 400")

